import{_ as l,c as a,o as e,a1 as o}from"./chunks/framework.DDNAyvCW.js";const t="/assets/mobile_ai.DJZjJhrB.jpg",r="/assets/mobile_ai_chat.CwiMLhOq.jpg",c="/assets/mobile_ai_term.Cnf6FbpV.jpg",b=JSON.parse('{"title":"AI 对话","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/ai-agent/index.md","filePath":"docs/mobile/ai-agent/index.md"}'),d={name:"docs/mobile/ai-agent/index.md"};function s(n,i,p,_,h,m){return e(),a("div",null,i[0]||(i[0]=[o('<h1 id="ai-对话" tabindex="-1">AI 对话 <a class="header-anchor" href="#ai-对话" aria-label="Permalink to &quot;AI 对话&quot;">​</a></h1><p>AI 对话功能帮助你在手机上完成命令执行、问题排查和日常运维咨询。</p><p>移动端目前主要包含两种模式：<code>对话</code> 和 <code>终端</code>。你可以通过输入框底部的模式选择器在两者之间切换。</p><p><img src="'+t+'" alt=""></p><h2 id="对话模式" tabindex="-1">对话模式 <a class="header-anchor" href="#对话模式" aria-label="Permalink to &quot;对话模式&quot;">​</a></h2><p><code>对话</code> 模式用于与 AI 协作完成分析、解释和命令建议。</p><p>使用说明：</p><ul><li>需要先登录账号</li><li>需要在个人中心选择可用模型</li><li>支持文字输入</li><li>支持语音输入</li><li>AI 可以解析自然语言并生成可执行命令</li><li>AI 可以根据当前上下文持续协助排查问题</li></ul><p>适合场景：</p><ul><li>学习 Linux 命令</li><li>获取故障排查建议</li><li>请求脚本编写辅助</li><li>理解配置文件含义</li><li>咨询运维最佳实践</li></ul><p><img src="'+r+'" alt=""></p><h2 id="终端模式" tabindex="-1">终端模式 <a class="header-anchor" href="#终端模式" aria-label="Permalink to &quot;终端模式&quot;">​</a></h2><p><code>终端</code> 模式直接执行命令，不经过 AI 处理。</p><p>使用说明：</p><ul><li>需要先连接服务器</li><li>未连接时，页面会显示连接主机的入口</li><li>支持文字输入</li><li>支持语音输入</li><li>直接返回命令执行结果</li></ul><p>适合场景：</p><ul><li>临时执行一条命令</li><li>快速查看主机状态</li></ul><p><img src="'+c+'" alt=""></p><h2 id="典型使用流程" tabindex="-1">典型使用流程 <a class="header-anchor" href="#典型使用流程" aria-label="Permalink to &quot;典型使用流程&quot;">​</a></h2><ol><li>打开 AI 对话页</li><li>连接目标主机</li><li>选择 <code>对话</code> 或 <code>终端</code></li><li>输入问题或命令，或通过语音发起请求</li><li>查看返回结果，按需继续追问</li></ol><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>需要解释、规划和排障时，优先使用 <code>对话</code> 模式</li><li>登录后先在个人中心确认模型设置，避免进入 <code>对话</code> 模式后无法使用</li></ul>',22)]))}const f=l(d,[["render",s]]);export{b as __pageData,f as default};
